const thermalResult = $('Get Thermal Analysis').first().json;
const pueResult = $('Get PUE Data').first().json;

const thermal = thermalResult.result || thermalResult;
const pueData = pueResult.result || pueResult;

// Analyze thermal status
const hotspots = thermal.hotspots || [];
const criticalHotspots = hotspots.filter(h => h.status === 'critical');
const warningHotspots = hotspots.filter(h => h.status === 'warning');

// Determine overall status
let overallStatus = 'healthy';
let alertLevel = 'none';
let message = 'All thermal readings within normal range.';

if (criticalHotspots.length > 0) {
  overallStatus = 'critical';
  alertLevel = 'critical';
  message = `CRITICAL: ${criticalHotspots.length} location(s) exceeding temperature limits!`;
} else if (warningHotspots.length > 0) {
  overallStatus = 'warning';
  alertLevel = 'warning';
  message = `WARNING: ${warningHotspots.length} location(s) approaching temperature limits.`;
}

// Add PUE context
const currentPUE = pueData[0]?.pue || pueData.pue || null;
let pueStatus = 'unknown';
if (currentPUE) {
  if (currentPUE > 2.0) pueStatus = 'critical';
  else if (currentPUE > 1.8) pueStatus = 'poor';
  else if (currentPUE > 1.5) pueStatus = 'average';
  else if (currentPUE > 1.3) pueStatus = 'good';
  else pueStatus = 'excellent';
}

return {
  json: {
    overallStatus,
    alertLevel,
    message,
    thermal: {
      averageTemp: thermal.summary?.averageTemperature,
      maxTemp: thermal.summary?.maxTemperature,
      minTemp: thermal.summary?.minTemperature,
      hotspotCount: hotspots.length,
      criticalCount: criticalHotspots.length,
      warningCount: warningHotspots.length,
      ashraeCompliance: thermal.summary?.ashraeCompliantPercent
    },
    hotspots: hotspots.slice(0, 10),
    recommendations: thermal.recommendations || [],
    pue: {
      current: currentPUE,
      status: pueStatus,
      itPowerKw: pueData[0]?.itPowerKw,
      facilityPowerKw: pueData[0]?.facilityPowerKw
    },
    timestamp: new Date().toISOString()
  }
};
